class Leaf:
    def __init__(self, n):
        self.n = n
    def total(self):
        return self.n

class Box:
    def __init__(self):
        self.items = []
    def add(self, x):
        self.items.append(x)
    def total(self):
        return sum(i.total() for i in self.items)

b = Box()
b.add(Leaf(2))
b.add(Leaf(3))
print(b.total())

